#!/bin/bash
IFS=. read -r i1 i2 i3 i4 <<< "$1"; n=$2; m1=$((n>=8?255:(n<=0?0:(256-(1<<(8-n)))))); m2=$((n>=16?255:(n<=8?0:(256-(1<<(16-n)))))); m3=$((n>=24?255:(n<=16?0:(256-(1<<(24-n)))))); m4=$((n>=32?255:(n<=24?0:(256-(1<<(32-n)))))); printf "%d.%d.%d.%d - %d.%d.%d.%d" "$((i1&m1))" "$((i2&m2))" "$((i3&m3))" "$(((i4&m4)+1))" "$((i1|(255-m1)))" "$((i2|(255-m2)))" "$((i3|(255-m3)))" "$(((i4|(255-m4))-1))"
